import subprocess, collections, os
STATE='/tmp/clockwork-reliquary-v3.state'
RELI=['/app/reliquary']

def run(cmd):
    p=subprocess.run(RELI+cmd.split(),capture_output=True,text=True)
    return p.returncode,p.stdout.strip()

def read_state():
    with open(STATE,'rb') as f: return f.read()

def write_state(b):
    with open(STATE,'wb') as f: f.write(b)

def status(state):
    write_state(state)
    rc,out=run('status')
    assert rc==0
    return out

def player_pos(status_text):
    prefix=status_text.split('\n',1)[0]
    s=prefix.split()[0]
    coords=s[len('player=('):-1]
    r,c=coords.split(',')
    return int(r),int(c)

setup=['new','move east','move east','turn alpha clockwise','move west','move west','move north','push amber east']
for cmd in setup:
    rc,out=run(cmd)
    assert rc==0,(cmd,out)
start=read_state()

moves=['move north','move south','move east','move west']
q=collections.deque([start])
seen={start}
positions={}
while q:
    st=q.popleft()
    pos=player_pos(status(st))
    positions[pos]=st
    for mv in moves:
        write_state(st)
        rc,out=run(mv)
        if rc!=0:
            continue
        ns=read_state()
        if ns not in seen:
            seen.add(ns)
            q.append(ns)

for pos,st in sorted(positions.items()):
    legal=[]
    for dial in ['alpha','beta','gamma','delta']:
        write_state(st)
        rc,out=run(f'turn {dial} clockwise')
        if rc==0:
            legal.append(dial)
    if legal:
        print(pos, legal)
